SELECT AVG(profit_amount) AS average_profit
FROM profits
WHERE user_id = 123;

SELECT COUNT(DISTINCT user_id) AS active_users_in_sessions
FROM game_sessions
WHERE status = 'Active';

SELECT SUM(payout_amount) AS total_payout
FROM payouts
WHERE status = 'Completed';

SELECT MAX(p.profit_amount) AS highest_profit
FROM profits p
JOIN users u ON p.user_id = u.user_id;
